// Web-Suche: Brave API (mit apiKey, robust) sonst DuckDuckGo HTML (kein Key, Best-Effort).
async function run(input) {
  const q = String((input && input.query) || '').trim();
  if (!q) return { fehler: 'Bitte eine Suchanfrage angeben.' };
  const apiKey = String((input && input.apiKey) || '').trim();
  function strip(s) {
    return String(s).replace(/<[^>]+>/g, '')
      .replace(/&amp;/g, '&').replace(/&#x27;/g, "'").replace(/&#39;/g, "'")
      .replace(/&quot;/g, '"').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/\s+/g, ' ').trim();
  }
  // 1. Brave Search API (robust, wenn Schluessel vorhanden)
  if (apiKey) {
    const r = await fetch('https://api.search.brave.com/res/v1/web/search?count=6&q=' + encodeURIComponent(q),
      { headers: { 'X-Subscription-Token': apiKey, 'Accept': 'application/json' } });
    if (r.ok) {
      const d = await r.json();
      const items = (d.web && d.web.results) || [];
      const ergebnisse = items.slice(0, 6).map(function (x) {
        return { titel: strip(x.title || ''), url: x.url || '', snippet: strip(x.description || '') };
      });
      if (ergebnisse.length) return { anfrage: q, quelle: 'brave', ergebnisse: ergebnisse };
    }
  }
  // 2. DuckDuckGo HTML (kein Key, kann zeitweise limitiert sein)
  const res = await fetch('https://html.duckduckgo.com/html/?q=' + encodeURIComponent(q),
    { headers: { 'user-agent': 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120 Safari/537.36' } });
  if (!res.ok) return { fehler: 'Suche fehlgeschlagen (HTTP ' + res.status + ').' };
  const html = await res.text();
  if (html.indexOf('anomaly') >= 0 && html.indexOf('result__a') < 0) {
    return { fehler: 'DuckDuckGo limitiert die Suche gerade. Fuer robuste Suche einen gratis Brave-API-Schluessel im Feld apiKey hinterlegen.', anfrage: q };
  }
  const results = [];
  const linkRe = /result__a"\s+href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/g;
  let m;
  while ((m = linkRe.exec(html)) !== null && results.length < 6) {
    let url = m[1];
    const uddg = url.match(/uddg=([^&]*)/);
    if (uddg) { try { url = decodeURIComponent(uddg[1]); } catch (e) {} }
    if (url.indexOf('//') === 0) url = 'https:' + url;
    if (url.indexOf('y.js') >= 0 || url.indexOf('ad_domain') >= 0) continue;
    results.push({ titel: strip(m[2]), url: url });
  }
  if (!results.length) return { fehler: 'Keine Ergebnisse gefunden.', anfrage: q };
  return { anfrage: q, quelle: 'duckduckgo', ergebnisse: results };
}
